    h = G.copy()
    # Remove edges with None cost
    edges_to_remove = [(u, v) for u, v, d in h.edges(data=True) if d.get('cost') is None]
    h.remove_edges_from(edges_to_remove)
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))

    terminals = [src] + list(dsts)

    # Compute shortest paths between all pairs of terminals
    sp_cache = {}  # (u, v) -> (cost, path)
    for u in terminals:
        try:
            lengths, paths = nx.single_source_dijkstra(h, u, weight='cost')
        except Exception:
            continue
        for v in terminals:
            if v != u and v in lengths:
                sp_cache[(u, v)] = (lengths[v], paths[v])

    # Strategy 1: Independent shortest paths (baseline)
    baseline_topology = _build_independent_paths(src, dsts, h, G, num_partitions, sp_cache)
    baseline_cost = _compute_tree_cost(baseline_topology, G)

    # Strategy 2: MSA-based Steiner tree
    msa_topology = _build_msa_tree(src, dsts, h, G, num_partitions, terminals, sp_cache)
    msa_cost = _compute_tree_cost(msa_topology, G)

    # Strategy 3: Greedy relay tree - add destinations one by one to minimize marginal cost
    greedy_topology = _build_greedy_tree(src, dsts, h, G, num_partitions, sp_cache)
    greedy_cost = _compute_tree_cost(greedy_topology, G)

    # Pick the best strategy
    best_cost = baseline_cost
    best_topology = baseline_topology
    if msa_cost < best_cost:
        best_cost = msa_cost
        best_topology = msa_topology
    if greedy_cost < best_cost:
        best_cost = greedy_cost
        best_topology = greedy_topology

    return best_topology


