            if u != v and (u, v) in sp_cache:
                cost, _ = sp_cache[(u, v)]
                metric_closure.add_edge(u, v, weight=cost)

    # Find minimum spanning arborescence rooted at src
    try:
        msa = nx.minimum_spanning_arborescence(metric_closure, attr='weight')
    except Exception:
