        for i in range(len(tree_path) - 1):
            u, v = tree_path[i], tree_path[i + 1]
            if (u, v) in sp_cache:
                _, actual_path = sp_cache[(u, v)]
            else:
                try:
                    actual_path = nx.dijkstra_path(h, u, v, weight='cost')
                except Exception:
                    continue

