                    best_dst = dst
                    best_connection_node = tree_node
                    break
                if dst not in all_sp_lengths.get(tree_node, {}):
                    continue

                # Get path from tree_node to dst
                path = all_sp_paths[tree_node][dst]
                # Compute marginal cost: edges not already in tree
                marginal_cost = 0
                for i in range(len(path) - 1):
                    edge = (path[i], path[i + 1])
                    if edge not in tree_edges:
                        edge_cost = G[edge[0]][edge[1]].get('cost', 0) or 0
                        marginal_cost += edge_cost

                if marginal_cost < best_marginal_cost:
                    best_marginal_cost = marginal_cost
                    best_dst = dst
                    best_connection_node = tree_node

            if best_marginal_cost == 0:
                break

        if best_dst is None:
            break

        remaining_dsts.remove(best_dst)

        if best_connection_node == best_dst:
            # dst is already in tree
            dst_full_paths[best_dst] = node_path_from_src.get(best_dst, [])
            continue

        # Get path from connection node to dst
        path = all_sp_paths[best_connection_node][best_dst]

        # Full path from src = path_from_src_to_connection_node + path_from_connection_to_dst
        prefix_path = node_path_from_src.get(best_connection_node, [])
        new_edges = []
        for i in range(len(path) - 1):
            edge = (path[i], path[i + 1])
            new_edges.append(edge)
            tree_edges.add(edge)
            # Add intermediate nodes to tree
            if path[i] not in tree_nodes:
                tree_nodes.add(path[i])
                node_path_from_src[path[i]] = prefix_path + new_edges[:len(new_edges)-1]

        tree_nodes.add(best_dst)
        full_path = prefix_path + new_edges
        dst_full_paths[best_dst] = full_path
        node_path_from_src[best_dst] = full_path

