    """MSA approach with extended relay candidates (nodes on shortest paths)"""
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Find relay candidates: nodes on any shortest path from src to any dst
    relay_candidates = set()
    relay_candidates.add(src)
    for dst in dsts:
        relay_candidates.add(dst)
        if dst in all_sp_paths.get(src, {}):
            for node in all_sp_paths[src][dst]:
                relay_candidates.add(node)

    # Also add nodes on shortest paths between destinations
    for d1 in dsts:
        for d2 in dsts:
            if d1 != d2 and d2 in all_sp_paths.get(d1, {}):
                for node in all_sp_paths[d1][d2]:
                    relay_candidates.add(node)

    terminals_extended = list(relay_candidates)

    # Build metric closure on extended terminals
    metric_closure = nx.DiGraph()
    for u in terminals_extended:
        for v in terminals_extended:
            if u != v and v in all_sp_lengths.get(u, {}):
                metric_closure.add_edge(u, v, weight=all_sp_lengths[u][v])

