def _find_path_in_edges(src, target, edges_set):
    """Find path from src to target using only edges in edges_set (BFS)"""
    if src == target:
        return []
    # Build adjacency from edges_set
    adj = {}
    for u, v in edges_set:
        if u not in adj:
            adj[u] = []
        adj[u].append(v)

    # BFS
    visited = {src}
    queue = [(src, [])]
    while queue:
        node, path = queue.pop(0)
        for neighbor in adj.get(node, []):
            if neighbor == target:
                return path + [(node, neighbor)]
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [(node, neighbor)]))
    return None


