    """Get list of (u,v) tuples for shortest path from src_node to dst_node"""
    if dst_node not in all_sp_paths.get(src_node, {}):
        return None
    path = all_sp_paths[src_node][dst_node]
    return [(path[i], path[i+1]) for i in range(len(path)-1)]


def _build_greedy_tree_paths(src, dsts, G, all_sp_lengths, all_sp_paths):
    """Greedy: add destination with minimum marginal cost to existing tree"""
