    remaining = list(dsts)

    while remaining:
        best_dst = None
        best_mc = float('inf')
        best_conn = None

        for dst in remaining:
            for tn in tree_nodes:
                if tn == dst:
                    best_mc = 0
                    best_dst = dst
                    best_conn = tn
                    break
                edges = _get_path_edges(tn, dst, all_sp_paths)
                if edges is None:
                    continue
                mc = sum((G[u][v].get('cost', 0) or 0) for u, v in edges if (u, v) not in tree_edges)
                if mc < best_mc:
                    best_mc = mc
                    best_dst = dst
                    best_conn = tn
