        remaining.remove(best_dst)

        if best_conn == best_dst:
            dst_paths[best_dst] = node_path_from_src.get(best_dst, [])
            continue

        edges = _get_path_edges(best_conn, best_dst, all_sp_paths)
        if edges is None:
